# Export source RG RBAC assignments before move
$assignments = Get-AzRoleAssignment -ResourceGroupName $sourceRG -Scope "/subscriptions/$sourceSub/resourceGroups/$sourceRG"
$assignments | Select-Object DisplayName, RoleDefinitionName, SignInName | Export-Csv -Path /tmp/pre-move-rbac.csv -NoTypeInformation

# After the move, recreate assignments on destination RG
$assignments | ForEach-Object {
    $params = @{
        ObjectId           = $_.ObjectId
        RoleDefinitionName = $_.RoleDefinitionName
        Scope              = "/subscriptions/$destSub/resourceGroups/$destRG"
    }
    try {
        New-AzRoleAssignment @params | Out-Null
        Write-Host "Assigned $($_.RoleDefinitionName) to $($_.SignInName)"
    } catch {
        Write-Warning "Failed to assign $($_.RoleDefinitionName) to $($_.SignInName): $_"
    }
}
